code.C++:
class Solution {
public:
    string checkArray(vector<int>& A) {
        int odd_count = 0;
        for (int x : A) {
            if (x & 1) odd_count++;
        }
        return (odd_count & 1) ? "NO" : "YES";
    }
};

code.Python3:
class Solution:
    def check_array(self, A):
        odd_count = sum(1 for x in A if x % 2 == 1)
        return "NO" if odd_count % 2 == 1 else "YES"

code.C:
const char* checkArray(int N, int A[]) {
    int odd_count = 0;
    for (int i = 0; i < N; ++i) {
        if (A[i] % 2 == 1) {
            odd_count++;
        }
    }
    return (odd_count % 2 == 1) ? "NO" : "YES";
}

code.Java:
class Solution {
    public String checkArray(int[] A) {
        int odd_count = 0;
        for (int num : A) {
            if ((num & 1) == 1) {
                odd_count++;
            }
        }
        return (odd_count & 1) == 1 ? "NO" : "YES";
    }
}

code.JavaScript:
class Solution {
    checkArray(arr) {
        let oddCount = 0;
        for (let num of arr) {
            if (num % 2 !== 0) oddCount++;
        }
        return (oddCount % 2 !== 0) ? "NO" : "YES";
    }
